insert into public.exercises (id, name, muscle_group, equipment, target, secondary_muscles, instructions, gif_path) values
  ('db-0358', 'dumbbell one arm reverse wrist curl', 'Arms', 'Dumbbell', 'forearms', ARRAY['wrist extensors']::text[], ARRAY['Sit on a bench or chair with your feet flat on the ground.','Hold a dumbbell in one hand with an overhand grip, palm facing down.','Rest your forearm on your thigh, with your wrist hanging off the edge.','Slowly lower the dumbbell towards the ground by flexing your wrist.','Pause for a moment at the bottom, then slowly curl your wrist back up towards your body.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'BwSNDGt'),
  ('db-0359', 'dumbbell one arm reverse fly (with support)', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Sit on a bench with your feet flat on the ground and your back straight.','Hold a dumbbell in one hand with your palm facing inwards.','Lean forward and place your free hand on the bench for support.','Keep your arm slightly bent and raise it out to the side until it is parallel to the ground.','Pause for a moment at the top, then slowly lower your arm back down to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'e25F58f'),
  ('db-1622', 'dumbbell one arm reverse grip press', 'Chest', 'Dumbbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Sit on a flat bench with a dumbbell in one hand, palm facing towards your body.','Place your feet flat on the ground and keep your back straight.','Raise the dumbbell to shoulder height, keeping your elbow close to your body.','Press the dumbbell upwards until your arm is fully extended.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'Ze7MoIb'),
  ('db-1414', 'dumbbell one arm reverse preacher curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a preacher bench with your chest against the pad and your arm extended over the edge of the bench, holding a dumbbell with an underhand grip.','Lower the dumbbell slowly until your arm is fully extended.','Curl the dumbbell back up towards your shoulder, keeping your upper arm stationary.','Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'bWxq4op'),
  ('db-1667', 'dumbbell one arm reverse spider curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with a dumbbell in one hand, palm facing down and arm fully extended.','Keeping your upper arm stationary, curl the dumbbell towards your shoulder by flexing your elbow.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'VdLZ3nB'),
  ('db-1668', 'dumbbell one arm seated bicep curl on exercise ball', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back straight.','Hold a dumbbell in one hand with your palm facing up and your arm fully extended.','Keeping your upper arm stationary, curl the dumbbell towards your shoulder by contracting your biceps.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 's999Hdo'),
  ('db-1669', 'dumbbell one arm seated hammer curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a dumbbell in one hand with a neutral grip (palms facing each other).','Rest your elbow on the inside of your thigh, just above the knee.','Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.','Pause for a moment at the top, squeezing your biceps.','Inhale and slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'jK2hZ6n'),
  ('db-1415', 'dumbbell one arm seated neutral wrist curl', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up.','Rest your forearm on your thigh, allowing your wrist to hang off the edge.','Keeping your forearm stationary, curl your wrist upward as far as possible.','Pause for a moment at the top, then slowly lower your wrist back down to the starting position.','Repeat for the desired number of repetitions, then switch to the other hand.']::text[], 'YtaCTYl'),
  ('db-0361', 'dumbbell one arm shoulder press', 'Shoulders', 'Dumbbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward.','Press the dumbbell upward until your arm is fully extended overhead.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], '84RyJf8'),
  ('db-0360', 'dumbbell one arm shoulder press v. 2', 'Shoulders', 'Dumbbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward.','Engage your core and press the dumbbell straight up overhead, fully extending your arm.','Pause for a moment at the top, then slowly lower the dumbbell back to shoulder level.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], '1TkiAFK'),
  ('db-3888', 'dumbbell one arm snatch', 'Legs', 'Dumbbell', 'glutes', ARRAY['hamstrings','quadriceps','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip.','Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.','Lower the dumbbell towards the ground, keeping it close to your body.','Explosively extend your hips, knees, and ankles, driving the dumbbell upwards in a straight line.','As the dumbbell reaches shoulder height, quickly rotate your hand and punch it overhead, fully extending your arm.','Catch the dumbbell overhead with a slight bend in your knees and hips.','Lower the dumbbell back down to the starting position in a controlled manner.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], '6pTkI99'),
  ('db-1670', 'dumbbell one arm standing curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with a dumbbell in one hand, palm facing forward and arm fully extended.','Keeping your upper arm stationary, exhale and curl the weight upward while contracting your biceps.','Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'ffQsyBj'),
  ('db-1671', 'dumbbell one arm standing hammer curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with a dumbbell in each hand, palms facing your torso.','Keep your elbows close to your torso and your upper arms stationary.','Exhale and curl the weights while contracting your biceps.','Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], '2sQGZ5b'),
  ('db-0362', 'dumbbell one arm triceps extension (on bench)', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a dumbbell in one hand and place your other hand on the bench for support.','Raise the dumbbell overhead, keeping your upper arm close to your head and your elbow pointing forward.','Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary.','Extend your arm back up to the starting position, fully straightening your elbow.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'nAuHPcD'),
  ('db-0363', 'dumbbell one arm upright row', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip.','Let the dumbbell hang at arm''s length in front of your thighs, with your palm facing your body.','Keeping your back straight and your core engaged, exhale and lift the dumbbell straight up towards your chin, leading with your elbow.','Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], '6cKQC5E'),
  ('db-0364', 'dumbbell one arm wrist curl', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench or chair with your feet flat on the ground.','Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh.','Allow your wrist to extend, letting the dumbbell roll down towards your fingers.','Slowly curl your wrist back up, bringing the dumbbell towards your forearm.','Repeat for the desired number of repetitions, then switch to the other hand.']::text[], 'q8aHNoF'),
  ('db-1672', 'dumbbell one arm zottman preacher curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a preacher curl bench and hold a dumbbell in one hand with an underhand grip.','Rest your upper arm on the preacher bench pad, allowing your arm to fully extend.','Curl the dumbbell up towards your shoulder, keeping your upper arm stationary.','At the top of the curl, rotate your wrist so that your palm faces up.','Slowly lower the dumbbell back down to the starting position, rotating your wrist back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'sxY5Biu'),
  ('db-1292', 'dumbbell one leg fly on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an exercise ball with a dumbbell in each hand, palms facing each other.','Place one foot on the ground and extend the other leg straight out in front of you.','Lean forward slightly and bring your arms out to the sides, keeping a slight bend in your elbows.','Slowly lower the dumbbells down and out to the sides, feeling a stretch in your chest.','Pause for a moment at the bottom, then squeeze your chest muscles to bring the dumbbells back up to the starting position.','Repeat for the desired number of repetitions, then switch legs and repeat.']::text[], 'pH2x2jj'),
  ('db-0365', 'dumbbell over bench neutral wrist curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.','Rest your forearms on the bench, allowing your wrists to hang off the edge.','Keeping your upper arms stationary, exhale and curl the dumbbells up towards your shoulders.','Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'BKa8dmT'),
  ('db-0366', 'dumbbell over bench one arm neutral wrist curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with a dumbbell in one hand and your arm extended over the bench, palm facing up.','Keep your upper arm stationary and curl the dumbbell towards your shoulder, keeping your wrist in a neutral position.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'IvV6C9M'),
  ('db-1441', 'dumbbell over bench one arm reverse wrist curl', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down.','Rest your forearm on the bench with your wrist hanging off the edge.','Slowly curl your wrist upwards, bringing the dumbbell towards your forearm.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], '4Jc36XM'),
  ('db-0367', 'dumbbell over bench one arm wrist curl', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','shoulders']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down.','Rest your forearm on the bench with your wrist hanging off the edge.','Slowly curl your wrist upwards, bringing the dumbbell towards your forearm.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'KI1DjNN'),
  ('db-0368', 'dumbbell over bench revers wrist curl', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing down.','Rest your forearms on the bench, allowing your wrists to hang off the edge.','Slowly curl your wrists upward, bringing the dumbbells towards your body.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '3tAXPQ6'),
  ('db-0369', 'dumbbell over bench wrist curl', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench with your forearms resting on the bench and your palms facing up, holding a dumbbell in each hand.','Allow your wrists to hang over the edge of the bench.','Slowly curl your wrists upward, squeezing your forearms at the top of the movement.','Pause for a moment, then slowly lower your wrists back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'D1xYJAU'),
  ('db-1329', 'dumbbell palm rotational bent over row', 'Back', 'Dumbbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.','Bend forward at the hips, keeping your back straight and your knees slightly bent.','Let your arms hang straight down, palms facing your body.','Engage your core and pull the dumbbells up towards your chest, keeping your elbows close to your body.','As you pull the dumbbells up, rotate your palms so they face away from your body.','Squeeze your shoulder blades together at the top of the movement.','Slowly lower the dumbbells back down to the starting position, rotating your palms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'wt6rwjk'),
  ('db-1623', 'dumbbell palms in incline bench press', 'Arms', 'Dumbbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Sit on the bench with your back against the backrest and feet flat on the ground.','Hold a dumbbell in each hand with an overhand grip, palms facing inwards.','Extend your arms straight up above your chest, keeping a slight bend in your elbows.','Lower the dumbbells slowly towards your shoulders, keeping your elbows close to your body.','Pause for a moment at the bottom, then press the dumbbells back up to the starting position.','Repeat for the desired number of repetitions.']::text[], '8eqjhOl'),
  ('db-0370', 'dumbbell peacher hammer curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with a dumbbell in each hand, palms facing your torso.','Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.','This will be your starting position.','Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Then, inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the recommended amount of repetitions.']::text[], 'F1KxjBa'),
  ('db-0371', 'dumbbell plyo squat', 'Legs', 'Dumbbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.','Lower your body into a squat position by bending your knees and pushing your hips back.','As you reach the bottom of the squat, explode upward, jumping off the ground.','While in the air, quickly switch the position of your feet, landing with your opposite foot forward.','Immediately lower your body back into a squat position and repeat the jump, switching your feet again.','Continue alternating the position of your feet with each jump for the desired number of repetitions.']::text[], 'S4pwGlc'),
  ('db-0372', 'dumbbell preacher curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a preacher curl bench with your upper arms resting on the pad and your chest against it.','Hold a dumbbell in each hand with your palms facing up and your arms fully extended.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'jivWf8n'),
  ('db-1673', 'dumbbell preacher curl over exercise ball', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back straight.','Hold a dumbbell in one hand with an underhand grip, resting your elbow on the exercise ball.','Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.','Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'hwygydB'),
  ('db-1293', 'dumbbell press on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and dumbbells in each hand, resting on your thighs.','Slowly walk your feet forward, rolling the exercise ball until your lower back is supported on the ball and your knees are at a 90-degree angle.','Raise the dumbbells to shoulder height, palms facing forward.','Press the dumbbells upward until your arms are fully extended.','Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'O8o7q4d'),
  ('db-0373', 'dumbbell pronate-grip triceps extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench or chair with your back straight and feet flat on the ground.','Hold a dumbbell with both hands, palms facing down, and extend your arms straight up overhead.','Keeping your upper arms close to your head and elbows pointing forward, slowly lower the dumbbell behind your head by bending your elbows.','Pause for a moment, then extend your arms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bpJL2Qs'),
  ('db-0374', 'dumbbell prone incline curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the bench to a 45-degree incline.','Lie face down on the bench with your chest and stomach resting against it.','Hold a dumbbell in each hand with your palms facing down and your arms fully extended.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'mwpPcr1'),
  ('db-1674', 'dumbbell prone incline hammer curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the bench to a 45-degree incline.','Lie face down on the bench with a dumbbell in each hand, palms facing each other.','Allow your arms to hang straight down towards the floor, keeping your elbows slightly bent.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'cWemPG8'),
  ('db-0375', 'dumbbell pullover', 'Chest', 'Dumbbell', 'pectorals', ARRAY['latissimus dorsi','triceps']::text[], ARRAY['Lie flat on a bench with your head at one end and your feet on the floor.','Hold a dumbbell with both hands and extend your arms straight above your chest.','Keeping a slight bend in your elbows, slowly lower the dumbbell behind your head until you feel a stretch in your chest and shoulders.','Pause for a moment, then raise the dumbbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], '9XjtHvS'),
  ('db-1294', 'dumbbell pullover hip extension on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and the dumbbell resting on your thighs.','Slowly walk your feet forward, rolling the exercise ball down your back until your head, neck, and upper back are supported on the ball.','Hold the dumbbell with both hands and extend your arms straight up over your chest, keeping a slight bend in your elbows.','Lower the dumbbell behind your head, keeping your arms straight and maintaining control.','Pause for a moment, then raise the dumbbell back to the starting position.','While keeping your arms extended, lift your hips off the ground, squeezing your glutes and engaging your core.','Lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'lI7easp'),
  ('db-1295', 'dumbbell pullover on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['triceps','latissimus dorsi']::text[], ARRAY['Sit on an exercise ball and hold a dumbbell with both hands above your chest, arms extended.','Slowly lower the dumbbell behind your head while keeping your arms straight.','Pause for a moment, then raise the dumbbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'FSD6PGL'),
  ('db-1700', 'dumbbell push press', 'Shoulders', 'Dumbbell', 'delts', ARRAY['triceps','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level.','Bend your knees slightly and dip your body down, then explosively extend your legs and press the dumbbells overhead.','Lock out your arms at the top of the movement, then lower the dumbbells back to shoulder level.','Repeat for the desired number of repetitions.']::text[], 'FS63wTN'),
  ('db-0376', 'dumbbell raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','rhomboids']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.','Keep your back straight and engage your core.','Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'c9MnDRp'),
  ('db-2292', 'dumbbell rear delt raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'mu5Guxt'),
  ('db-0377', 'dumbbell rear delt row_shoulder', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.','Hold a dumbbell in each hand with your palms facing your body.','Bend forward at the waist, keeping your back straight and your core engaged.','Extend your arms straight down towards the floor, with a slight bend in your elbows.','Raise the dumbbells out to the sides, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'EKXOMEh'),
  ('db-0378', 'dumbbell rear fly', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Extend your arms straight down towards the ground, palms facing each other.','Keeping a slight bend in your elbows, lift your arms out to the sides and squeeze your shoulder blades together.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '8DiFDVA'),
  ('db-0380', 'dumbbell rear lateral raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','rhomboids']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.','Bend your knees slightly and hinge forward at the hips, keeping your back straight and core engaged.','Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'v1qBec9'),
  ('db-0379', 'dumbbell rear lateral raise (support head)', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','rhomboids']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'UzkLrem'),
  ('db-0381', 'dumbbell rear lunge', 'Legs', 'Dumbbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand.','Take a step backward with your right foot, lowering your body into a lunge position.','Bend your left knee and lower your body until your left thigh is parallel to the ground.','Pause for a moment, then push through your left heel to return to the starting position.','Repeat on the other side, stepping back with your left foot.']::text[], 'SSsBDwB'),
  ('db-0382', 'dumbbell revers grip biceps curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'e4ojVhP'),
  ('db-1624', 'dumbbell reverse bench press', 'Chest', 'Dumbbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your knees bent.','Hold a dumbbell in each hand with an overhand grip, palms facing towards your feet.','Extend your arms straight up towards the ceiling, keeping a slight bend in your elbows.','Slowly lower the dumbbells towards your chest, allowing your elbows to flare out to the sides.','Pause for a moment at the bottom, then push the dumbbells back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'UIbGx6H'),
  ('db-0383', 'dumbbell reverse fly', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Extend your arms straight down in front of you, palms facing each other.','Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'EAs3xL9'),
  ('db-1330', 'dumbbell reverse grip incline bench one arm row', 'Back', 'Dumbbell', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Place a dumbbell on the floor next to the bench.','Stand facing the bench with your feet shoulder-width apart.','Bend at the waist and place your left knee and left hand on the bench for support.','Pick up the dumbbell with your right hand using a reverse grip (palm facing down).','Keep your back straight and your core engaged.','Pull the dumbbell up towards your chest, keeping your elbow close to your body.','Squeeze your back muscles at the top of the movement.','Lower the dumbbell back down to the starting position in a controlled manner.','Repeat for the desired number of repetitions.','Switch sides and repeat the exercise with your left arm.']::text[], 'ZIViNh1'),
  ('db-1331', 'dumbbell reverse grip incline bench two arm row', 'Back', 'Dumbbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Sit on the bench with your chest against the backrest and your feet flat on the ground.','Hold a dumbbell in each hand with an underhand grip.','Lean forward and let your arms hang straight down, fully extended.','Pull the dumbbells up towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '9pQSkH8'),
  ('db-2327', 'dumbbell reverse grip row (female)', 'Back', 'Dumbbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.','Hold a dumbbell in each hand with an overhand grip, palms facing your body.','Bend forward at the waist, keeping your back straight and your core engaged.','Let your arms hang straight down, fully extended, with a slight bend in your elbows.','Pull the dumbbells up towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Nh3mvOO'),
  ('db-0384', 'dumbbell reverse preacher curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a preacher bench with your upper arms resting on the pad and your chest against the support.','Hold a dumbbell in each hand with an underhand grip, palms facing up.','Keeping your upper arms stationary, exhale and curl the dumbbells as you contract your biceps.','Continue to curl the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'O8Aq69u'),
  ('db-1675', 'dumbbell reverse spider curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with a dumbbell in each hand, palms facing your body and arms fully extended.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], '6sMAmNv'),
  ('db-0385', 'dumbbell reverse wrist curl', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench or chair with your feet flat on the ground.','Hold a dumbbell in each hand with an overhand grip, palms facing down.','Rest your forearms on your thighs, allowing your wrists to hang off the edge.','Slowly curl your wrists upward, bringing the dumbbells towards your body.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'BLCvwr2'),
  ('db-1459', 'dumbbell romanian deadlift', 'Legs', 'Dumbbell', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.','Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your knees to bend slightly.','Lower the dumbbells until you feel a stretch in your hamstrings, then push through your heels and engage your glutes to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'rR0LJzx'),
  ('db-0386', 'dumbbell rotation reverse fly', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing inwards.','Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.','Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.','Rotate your arms so that your palms are facing downwards.','Slowly lower your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'prbWx1D'),
  ('db-2397', 'dumbbell scott press', 'Shoulders', 'Dumbbell', 'delts', ARRAY['triceps','chest']::text[], ARRAY['Sit on a bench with a dumbbell in each hand, palms facing forward.','Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward.','Press the dumbbells upward until your arms are fully extended.','Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], '5vfAI0I'),
  ('db-0387', 'dumbbell seated alternate front raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','biceps']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a dumbbell in each hand with your palms facing your body and arms extended down by your sides.','Keeping your arms straight, raise one dumbbell in front of you until it is parallel to the ground.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat with the other arm.','Alternate between arms for the desired number of repetitions.']::text[], 'gH5fRsC'),
  ('db-1676', 'dumbbell seated alternate hammer curl on exercise ball', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back straight.','Hold a dumbbell in each hand with your palms facing your body and your arms fully extended.','Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while keeping your palm facing your body.','Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly lower the dumbbell back to the starting position.','Repeat the movement with the opposite arm.','Continue alternating arms for the desired number of repetitions.']::text[], 'QLRmNeT'),
  ('db-0388', 'dumbbell seated alternate press', 'Shoulders', 'Dumbbell', 'delts', ARRAY['triceps','chest']::text[], ARRAY['Sit on a bench with a dumbbell in each hand, palms facing forward.','Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward.','Press one dumbbell up overhead, fully extending your arm.','Lower the dumbbell back down to shoulder height.','Repeat with the other arm.','Continue alternating arms for the desired number of repetitions.']::text[], 'QT5Q0nK'),
  ('db-3546', 'dumbbell seated alternate shoulder', 'Shoulders', 'Dumbbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a dumbbell in each hand, palms facing inwards, and raise them to shoulder height.','Press one dumbbell up overhead while keeping the other dumbbell at shoulder height.','Lower the raised dumbbell back to shoulder height while simultaneously pressing the other dumbbell up overhead.','Continue alternating between arms for the desired number of repetitions.']::text[], 'q7qkONO'),
  ('db-0389', 'dumbbell seated bench extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a dumbbell with both hands and extend your arms straight up above your head.','Slowly lower the dumbbell behind your head, keeping your elbows close to your ears.','Pause for a moment, then raise the dumbbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'JhYSVwT'),
  ('db-2317', 'dumbbell seated bent arm lateral raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a dumbbell in each hand with your palms facing your body and your arms bent at a 90-degree angle.','Keeping your elbows bent, raise your arms out to the sides until they are parallel to the ground.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'JzQbv7J'),
  ('db-1730', 'dumbbell seated bent over alternate kickback', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders','back']::text[], ARRAY['Sit on a bench with a dumbbell in each hand, palms facing inwards.','Bend forward at the waist, keeping your back straight and parallel to the ground.','Extend one arm straight back, keeping it close to your body, until your arm is fully extended.','Pause for a moment, then slowly lower the dumbbell back to the starting position.','Repeat with the other arm.','Continue alternating arms for the desired number of repetitions.']::text[], 'x0lwvfq'),
  ('db-1737', 'dumbbell seated bent over triceps extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders','back']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand.','Bend forward at the waist, keeping your back straight and your head up.','Extend your arms straight back, keeping your elbows close to your head.','Pause for a moment, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], '4ievMJ9'),
  ('db-1677', 'dumbbell seated bicep curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.','Keep your back straight and your elbows close to your torso.','Exhale and curl the dumbbells up towards your shoulders, contracting your biceps.','Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'xiA6lRr'),
  ('db-0390', 'dumbbell seated biceps curl (on stability ball)', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a stability ball with your feet flat on the ground and your back straight.','Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.','Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'WgJnBH5'),
  ('db-3547', 'dumbbell seated biceps curl to shoulder press', 'Arms', 'Dumbbell', 'biceps', ARRAY['shoulders']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a dumbbell in each hand with your palms facing forward and arms fully extended.','Keeping your elbows close to your sides, curl the dumbbells up towards your shoulders.','Once your forearms are vertical, rotate your wrists so that your palms are facing forward.','Press the dumbbells overhead until your arms are fully extended.','Lower the dumbbells back down to the starting position by reversing the movement.','Repeat for the desired number of repetitions.']::text[], 'OeL23VY'),
  ('db-1379', 'dumbbell seated calf raise', 'Legs', 'Dumbbell', 'calves', ARRAY['hamstrings']::text[], ARRAY['Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs.','Place the balls of your feet on a raised surface such as a step or block, with your heels hanging off the edge.','Hold onto the dumbbell for stability.','Raise your heels as high as possible, lifting your body weight onto the balls of your feet.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'r29jP7S'),
  ('db-0391', 'dumbbell seated curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with your feet flat on the ground and a dumbbell in each hand, palms facing forward.','Keep your back straight and your elbows close to your torso.','Exhale and curl the dumbbells up towards your shoulders, contracting your biceps.','Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'TiaZTxx'),
  ('db-0392', 'dumbbell seated front raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','biceps']::text[], ARRAY['Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.','Keep your back straight and core engaged.','Raise the dumbbells in front of you, with your palms facing down, until they are at shoulder level.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Ys97II0'),
  ('db-1678', 'dumbbell seated hammer curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended straight down.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'IGtBdNT'),
  ('db-0393', 'dumbbell seated inner biceps curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.','Rest your upper arms on your thighs, allowing the dumbbells to hang down.','Keeping your upper arms stationary, curl the dumbbells up towards your shoulders by contracting your biceps.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'KXyoEtA'),
  ('db-0394', 'dumbbell seated kickback', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand.','Bend your knees slightly and lean forward from your hips, keeping your back straight.','Bring your upper arms close to your sides and keep your elbows bent at a 90-degree angle.','Extend your arms straight back, squeezing your triceps at the top of the movement.','Pause for a moment, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'en550rk'),
  ('db-0396', 'dumbbell seated lateral raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','upper back']::text[], ARRAY['Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.','Keep your back straight and core engaged.','Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'hxyTtWj'),
  ('db-0395', 'dumbbell seated lateral raise v. 2', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','triceps']::text[], ARRAY['Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.','Keep your back straight and core engaged.','Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'hrrS0Ed'),
  ('db-0397', 'dumbbell seated neutral wrist curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing each other.','Rest your forearms on your thighs, allowing the dumbbells to hang down.','Keeping your wrists in a neutral position, curl the dumbbells up towards your shoulders.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'uJmK7Z1'),
  ('db-1679', 'dumbbell seated one arm bicep curl on exercise ball with leg raised', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms','shoulders']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back straight.','Hold a dumbbell in one hand with your palm facing up and your arm fully extended.','Place your other hand on your hip for stability.','Slowly curl the dumbbell towards your shoulder, keeping your upper arm stationary.','Pause for a moment at the top of the movement, squeezing your bicep.','Slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions.','Switch arms and repeat the exercise.']::text[], '84sESNy'),
  ('db-0398', 'dumbbell seated one arm kickback', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand.','Bend your torso forward at the waist, keeping your back straight and parallel to the ground.','Extend your arm straight back, keeping your elbow close to your body.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'VQ3sNCn'),
  ('db-0399', 'dumbbell seated one arm rotate', 'Arms', 'Dumbbell', 'forearms', ARRAY['shoulders','biceps']::text[], ARRAY['Sit on a bench with your back straight and hold a dumbbell in one hand, resting it on your thigh.','Raise the dumbbell up to shoulder height, keeping your elbow close to your body.','Rotate your forearm outward, away from your body, while keeping your upper arm stationary.','Pause for a moment at the top, then slowly rotate your forearm back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], '7f2jsqP'),
  ('db-0400', 'dumbbell seated one leg calf raise', 'Legs', 'Dumbbell', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your right thigh.','Extend your left leg straight out in front of you, keeping your foot flexed.','Place the ball of your right foot on an elevated surface, such as a step or weight plate.','Using your calf muscles, raise your right heel as high as possible.','Pause for a moment at the top, then slowly lower your heel back down to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'Ia7tumC'),
  ('db-1380', 'dumbbell seated one leg calf raise - hammer grip', 'Legs', 'Dumbbell', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs.','Place one foot on a raised surface, such as a step or block, with your heel hanging off the edge.','Hold the dumbbell with a hammer grip, meaning your palms are facing each other and your fingers are wrapped around the handle.','Keeping your core engaged and your back straight, slowly raise your heel as high as possible by pushing through the ball of your foot.','Pause for a moment at the top, then slowly lower your heel back down to the starting position.','Repeat for the desired number of repetitions, then switch to the other leg.']::text[], 'FxhcxUW'),
  ('db-1381', 'dumbbell seated one leg calf raise - palm up', 'Legs', 'Dumbbell', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Sit on a bench or chair with your back straight and your feet flat on the ground.','Hold a dumbbell in one hand and place it on top of your thigh, palm facing up.','Lift one leg off the ground and extend it in front of you, keeping your knee slightly bent.','Raise your heel as high as possible by pushing through the ball of your foot.','Pause for a moment at the top, then slowly lower your heel back down.','Repeat for the desired number of repetitions, then switch legs and repeat.']::text[], 'VW88JNd'),
  ('db-0401', 'dumbbell seated palms up wrist curl', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','shoulders']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.','Rest your forearms on your thighs, allowing your wrists to hang off the edge.','Slowly curl your wrists upward, squeezing your forearms at the top of the movement.','Pause for a moment, then lower your wrists back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '2dImyQ8'),
  ('db-0402', 'dumbbell seated preacher curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a preacher curl bench with your feet flat on the floor.','Hold a dumbbell in one hand with an underhand grip, resting your upper arm against the preacher pad.','Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.','Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], '7D5bgLT'),
  ('db-0403', 'dumbbell seated revers grip concentration curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up.','Rest your elbow on the inside of your thigh, just above the knee.','Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder.','Pause for a moment at the top, squeezing your biceps.','Inhale and slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'lyKCLmK'),
  ('db-1738', 'dumbbell seated reverse grip one arm overhead tricep extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a dumbbell with an underhand grip and extend your arm straight up overhead.','Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary.','Pause for a moment, then extend your arm back up to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], '5fKX7wi'),
  ('db-0405', 'dumbbell seated shoulder press', 'Shoulders', 'Dumbbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Sit on a bench with a dumbbell in each hand, resting on your thighs.','Raise the dumbbells to shoulder height, palms facing forward.','Press the dumbbells upward until your arms are fully extended overhead.','Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height.','Repeat for the desired number of repetitions.']::text[], 'znQUdHY'),
  ('db-0404', 'dumbbell seated shoulder press (parallel grip)', 'Shoulders', 'Dumbbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Sit on a bench with a dumbbell in each hand, palms facing inward.','Raise the dumbbells to shoulder height, elbows bent and palms facing forward.','Press the dumbbells upward until your arms are fully extended overhead.','Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height.','Repeat for the desired number of repetitions.']::text[], 'f1jf47L'),
  ('db-2188', 'dumbbell seated triceps extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a dumbbell with both hands and extend your arms straight up overhead.','Bend your elbows and lower the dumbbell behind your head, keeping your upper arms close to your ears.','Pause for a moment, then straighten your arms and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'kont8Ut'),
  ('db-0406', 'dumbbell shrug', 'Back', 'Dumbbell', 'traps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body.','Keep your arms straight and let the dumbbells hang by your sides.','Raise your shoulders as high as possible, as if you are trying to touch your ears with your shoulders.','Hold the contraction for a second, then slowly lower your shoulders back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'NJzBsGJ'),
  ('db-0407', 'dumbbell side bend', 'Core', 'Dumbbell', 'abs', ARRAY['obliques']::text[], ARRAY['Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand, letting it hang down by your side.','Keeping your back straight and your core engaged, slowly bend sideways at the waist towards the opposite side of the dumbbell, lowering the weight as far as you comfortably can.','Pause for a moment, then slowly return to the starting position.','Repeat for the desired number of repetitions, then switch sides and repeat.']::text[], 'IpONWYv'),
  ('db-0408', 'dumbbell side lying one hand raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Lie on your side with your legs extended and your head supported by your arm.','Hold a dumbbell in your top hand with your palm facing down.','Keeping your arm straight, raise the dumbbell up to shoulder height.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'fTlkJop'),
  ('db-3664', 'dumbbell side plank with rear fly', 'Back', 'Dumbbell', 'upper back', ARRAY['shoulders','core']::text[], ARRAY['Start by lying on your side with your legs extended and stacked on top of each other.','Place your forearm on the ground directly below your shoulder, keeping your elbow bent at a 90-degree angle.','Hold a dumbbell in your top hand, with your arm extended straight down towards the ground.','Engage your core and lift your hips off the ground, creating a straight line from your head to your heels.','While maintaining the side plank position, lift the dumbbell up towards the ceiling, squeezing your shoulder blades together.','Lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'X6ytgYZ'),
  ('db-3548', 'dumbbell single arm overhead carry', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','core']::text[], ARRAY['Stand tall with your feet shoulder-width apart, holding a dumbbell in one hand.','Raise the dumbbell overhead, fully extending your arm.','Engage your core and keep your back straight as you walk forward, maintaining the dumbbell overhead.','Continue walking for the desired distance or time.','Switch hands and repeat the exercise.']::text[], 'mWBtgmb'),
  ('db-0409', 'dumbbell single leg calf raise', 'Legs', 'Dumbbell', 'calves', ARRAY['ankles']::text[], ARRAY['Stand on the edge of a step or platform with your heels hanging off and your toes on the step.','Hold a dumbbell in one hand and place your other hand on a wall or railing for support.','Raise your heel as high as possible, lifting your body up onto your toes.','Pause for a moment at the top, then slowly lower your heel back down below the step.','Repeat for the desired number of repetitions, then switch to the other leg.']::text[], '1kB3Wmk'),
  ('db-1757', 'dumbbell single leg deadlift', 'Legs', 'Dumbbell', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Stand with your feet hip-width apart, holding a dumbbell in your right hand.','Shift your weight onto your left leg and lift your right foot slightly off the ground.','Keeping your back straight, hinge forward at the hips and lower the dumbbell towards the ground.','At the same time, extend your right leg straight behind you, maintaining a slight bend in your left knee.','Lower the dumbbell until your torso and right leg are parallel to the ground.','Pause for a moment, then engage your glutes and hamstrings to return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'gKozT8X'),
  ('db-2805', 'dumbbell single leg deadlift with stepbox support', 'Legs', 'Dumbbell', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Stand with your feet hip-width apart, holding a dumbbell in your right hand.','Place your left foot on a stepbox or elevated surface behind you.','Keeping your back straight and core engaged, hinge forward at the hips, lowering the dumbbell towards the ground.','As you lower the dumbbell, simultaneously lift your left leg behind you, maintaining a straight line from head to heel.','Lower the dumbbell until you feel a stretch in your right hamstring, then return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'daBmy1Y'),
  ('db-0410', 'dumbbell single leg split squat', 'Legs', 'Dumbbell', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand.','Take a step forward with one foot and position your feet so that your front foot is flat on the ground and your back foot is elevated on a bench or step.','Lower your body by bending your front knee and hip, keeping your back knee slightly bent and your back heel off the ground.','Continue lowering until your front thigh is parallel to the ground, then push through your front heel to return to the starting position.','Repeat for the desired number of repetitions, then switch legs and repeat.']::text[], 'qx4fgX7'),
  ('db-0411', 'dumbbell single leg squat', 'Legs', 'Dumbbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand.','Extend one leg forward and keep it off the ground throughout the exercise.','Bend your standing leg and lower your body down as if sitting back into a chair.','Keep your chest up and your back straight.','Pause for a moment at the bottom, then push through your heel to return to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'H6ybluc')
